function useWallet() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { data: wallet, isLoading: isLoadingWallet } = useQuery({
    queryKey: [api.wallet.get.path],
    queryFn: async () => {
      const res = await fetch(api.wallet.get.path, { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch wallet");
      return await res.json();
    }
  });
  const transferMutation = useMutation({
    mutationFn: async (data) => {
      const res = await fetch(api.wallet.transfer.path, {
        method: api.wallet.transfer.method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
        credentials: "include"
      });
      if (!res.ok) {
        const error = await res.json();
        throw new Error(error.message || "Transfer failed");
      }
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [api.wallet.get.path] });
      queryClient.invalidateQueries({ queryKey: [api.explorer.transactions.path] });
      queryClient.invalidateQueries({ queryKey: [api.transactions.mine.path] });
      toast({
        title: "TRANSACTION CONFIRMED",
        description: "Funds transferred successfully.",
        className: "border-primary text-primary bg-black font-mono"
      });
    },
    onError: (error) => {
      toast({
        title: "TRANSACTION FAILED",
        description: error.message,
        variant: "destructive",
        className: "font-mono border-destructive bg-black text-destructive"
      });
    }
  });
  return {
    wallet,
    isLoadingWallet,
    transfer: transferMutation.mutate,
    isTransferring: transferMutation.isPending
  };
}

function useStaking() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { data: stakingInfo, isLoading: isLoadingInfo } = useQuery({
    queryKey: [api.staking.info.path],
    queryFn: async () => {
      const res = await fetch(api.staking.info.path, { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch staking info");
      return await res.json();
    },
    refetchInterval: 5e3
  });
  const { data: networkStats } = useQuery({
    queryKey: [api.staking.networkStats.path],
    queryFn: async () => {
      const res = await fetch(api.staking.networkStats.path, { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch network stats");
      return await res.json();
    },
    refetchInterval: 1e4
  });
  const stakeMutation = useMutation({
    mutationFn: async (amount) => {
      const res = await fetch(api.staking.stake.path, {
        method: api.staking.stake.method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount }),
        credentials: "include"
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || "Staking failed");
      }
      return await res.json();
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: [api.staking.info.path] });
      queryClient.invalidateQueries({ queryKey: [api.wallet.get.path] });
      queryClient.invalidateQueries({ queryKey: [api.transactions.mine.path] });
      toast({
        title: "MINING STARTED",
        description: data.message,
        className: "border-primary text-primary bg-black font-mono"
      });
    },
    onError: (error) => {
      toast({
        title: "Mining Error",
        description: error.message,
        variant: "destructive"
      });
    }
  });
  const unstakeMutation = useMutation({
    mutationFn: async (amount) => {
      const res = await fetch(api.staking.unstake.path, {
        method: api.staking.unstake.method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount }),
        credentials: "include"
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || "Unstaking failed");
      }
      return await res.json();
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: [api.staking.info.path] });
      queryClient.invalidateQueries({ queryKey: [api.wallet.get.path] });
      queryClient.invalidateQueries({ queryKey: [api.transactions.mine.path] });
      toast({
        title: "MINING STOPPED",
        description: data.message,
        className: "border-primary text-primary bg-black font-mono"
      });
    },
    onError: (error) => {
      toast({
        title: "Withdraw Error",
        description: error.message,
        variant: "destructive"
      });
    }
  });
  const claimMutation = useMutation({
    mutationFn: async () => {
      const res = await fetch(api.staking.claimRewards.path, {
        method: api.staking.claimRewards.method,
        headers: { "Content-Type": "application/json" },
        credentials: "include"
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        throw new Error(err.message || "Claiming rewards failed");
      }
      return await res.json();
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: [api.staking.info.path] });
      queryClient.invalidateQueries({ queryKey: [api.wallet.get.path] });
      queryClient.invalidateQueries({ queryKey: [api.transactions.mine.path] });
      toast({
        title: "MINING REWARDS CLAIMED!",
        description: data.message,
        className: "border-primary text-primary bg-black font-mono"
      });
    },
    onError: (error) => {
      toast({
        title: "Claim Error",
        description: error.message,
        variant: "destructive"
      });
    }
  });
  return {
    stakingInfo,
    networkStats,
    isLoadingInfo,
    stake: (amount) => stakeMutation.mutate(amount),
    unstake: (amount) => unstakeMutation.mutate(amount),
    claimRewards: () => claimMutation.mutate(),
    isStaking: stakeMutation.isPending,
    isUnstaking: unstakeMutation.isPending,
    isClaiming: claimMutation.isPending
  };
}

function useAddresses() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const { data: addresses, isLoading } = useQuery({
    queryKey: [api.wallet.addresses.list.path],
    queryFn: async () => {
      const res = await fetch(api.wallet.addresses.list.path, { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch addresses");
      return await res.json();
    }
  });
  const createMutation = useMutation({
    mutationFn: async (label) => {
      const res = await fetch(api.wallet.addresses.create.path, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ label: label || "New Wallet" }),
        credentials: "include"
      });
      if (!res.ok) throw new Error("Failed to create address");
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [api.wallet.addresses.list.path] });
      toast({
        title: "ADDRESS CREATED",
        description: "New wallet address generated with seed phrase.",
        className: "border-accent text-accent bg-card font-mono"
      });
    }
  });
  const getPhraseMutation = useMutation({
    mutationFn: async (id) => {
      const url = buildUrl(api.wallet.addresses.getPhrase.path, { id });
      const res = await fetch(url, { credentials: "include" });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.message || "Failed to get phrase");
      }
      return await res.json();
    },
    onError: (error) => {
      toast({
        title: "ERROR",
        description: error.message,
        variant: "destructive",
        className: "font-mono"
      });
    }
  });
  const lockMutation = useMutation({
    mutationFn: async (id) => {
      const url = buildUrl("/api/wallet/addresses/:id/lock", { id });
      const res = await fetch(url, { method: "PATCH", credentials: "include" });
      if (!res.ok) throw new Error("Failed to lock");
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [api.wallet.addresses.list.path] });
      toast({ title: "LOCKED", description: "Address locked. Seed phrase hidden.", className: "border-primary text-primary bg-card font-mono" });
    }
  });
  const unlockMutation = useMutation({
    mutationFn: async (id) => {
      const url = buildUrl("/api/wallet/addresses/:id/unlock", { id });
      const res = await fetch(url, { method: "PATCH", credentials: "include" });
      if (!res.ok) throw new Error("Failed to unlock");
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [api.wallet.addresses.list.path] });
      toast({ title: "UNLOCKED", description: "Address unlocked.", className: "border-accent text-accent bg-card font-mono" });
    }
  });
  const deleteMutation = useMutation({
    mutationFn: async (id) => {
      const url = buildUrl("/api/wallet/addresses/:id", { id });
      const res = await fetch(url, { method: "DELETE", credentials: "include" });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.message || "Failed to delete");
      }
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [api.wallet.addresses.list.path] });
      toast({ title: "DELETED", description: "Address removed.", className: "border-destructive text-destructive bg-card font-mono" });
    },
    onError: (error) => {
      toast({ title: "ERROR", description: error.message, variant: "destructive", className: "font-mono" });
    }
  });
  return {
    addresses,
    isLoading,
    createAddress: createMutation.mutate,
    isCreating: createMutation.isPending,
    getPhrase: getPhraseMutation.mutateAsync,
    isGettingPhrase: getPhraseMutation.isPending,
    lockAddress: lockMutation.mutate,
    unlockAddress: unlockMutation.mutate,
    deleteAddress: deleteMutation.mutate
  };
}

